 1→const API_BASE = 'http://localhost:8080';
 2→
 3→async function apiFetch(path: string, options?: RequestInit) {
 4→	const res = await fetch(`${API_BASE}${path}`, {
 5→		headers: { 'Content-Type': 'application/json' },
 6→		...options
 7→	});
 8→	if (!res.ok) {
 9→		const err = await res.json().catch(() => ({ error: { message: res.statusText } }));
10→		throw new Error(err.error?.message || res.statusText);
11→	}
12→	return res.json();
13→}
14→
15→export async function listApprovals(workspaceId = 'default') {
16→	return apiFetch(`/v1/approvals?workspace_id=${workspaceId}`);
17→}
18→
19→export async function getApproval(approvalId: string) {
20→	return apiFetch(`/v1/approvals/${approvalId}`);
21→}
22→
23→export async function approveRequest(approvalId: string, comment?: string) {
24→	return apiFetch(`/v1/approvals/${approvalId}/approve`, {
25→		method: 'POST',
26→		body: JSON.stringify({ comment })
27→	});
28→}
29→
30→export async function denyRequest(approvalId: string, reason: string, comment?: string) {
31→	return apiFetch(`/v1/approvals/${approvalId}/deny`, {
32→		method: 'POST',
33→		body: JSON.stringify({ reason, comment })
34→	});
35→}
