 1→<script lang="ts">
 2→	import { listPolicies } from '$lib/api';
 3→	import { onMount } from 'svelte';
 4→
 5→	let policies = $state<any[]>([]);
 6→	let loading = $state(true);
 7→	let error = $state('');
 8→
 9→	async function load() {
10→		try {
11→			const data = await listPolicies();
12→			policies = data.items || [];
13→		} catch (e: any) {
14→			error = e.message;
