 13→const (
 14→	// DefaultRegistryURL is the official MCP Registry API endpoint.
 15→	DefaultRegistryURL = "https://registry.modelcontextprotocol.io"
 16→
 17→	// DefaultCacheTTL is how long the server list is cached.
 18→	DefaultCacheTTL = 15 * time.Minute
 19→)
 20→
 21→// Client fetches and caches MCP server metadata from the official registry.
 22→type Client struct {
 23→	baseURL    string
 24→	httpClient *http.Client
 25→	cacheTTL   time.Duration
 26→
 27→	mu        sync.RWMutex
 28→	cached    []RegistryServer
 29→	cachedAt  time.Time
 30→}
 31→
 32→// NewClient creates a registry client with sensible defaults.
 33→func NewClient(httpClient *http.Client) *Client {
 34→	if httpClient == nil {
 35→		httpClient = &http.Client{Timeout: 30 * time.Second}
 36→	}
 37→	return &Client{
 38→		baseURL:    DefaultRegistryURL,
 39→		httpClient: httpClient,
 40→		cacheTTL:   DefaultCacheTTL,
 41→	}
 42→}
 43→
 44→// WithBaseURL overrides the registry URL (useful for testing).
 45→func (c *Client) WithBaseURL(url string) *Client {
 46→	c.baseURL = url
 47→	return c
 48→}
 49→
 50→// FetchAll returns every server from the registry, using the cache if fresh.
 51→func (c *Client) FetchAll(ctx context.Context) ([]RegistryServer, error) {
 52→	c.mu.RLock()
 53→	if c.cached != nil && time.Since(c.cachedAt) < c.cacheTTL {
 54→		result := make([]RegistryServer, len(c.cached))
 55→		copy(result, c.cached)
 56→		c.mu.RUnlock()
 57→		return result, nil
 58→	}
 59→	c.mu.RUnlock()
 60→
 61→	servers, err := c.fetchFromRegistry(ctx)
 62→	if err != nil {
 63→		return nil, err
 64→	}
 65→
 66→	c.mu.Lock()
 67→	c.cached = servers
 68→	c.cachedAt = time.Now()
 69→	c.mu.Unlock()
 70→
 71→	result := make([]RegistryServer, len(servers))
 72→	copy(result, servers)
 73→	return result, nil
 74→}
 75→
 76→// Search filters servers by a case-insensitive substring match on name or description.
 77→func (c *Client) Search(ctx context.Context, query string) ([]RegistryServer, error) {
 78→	all, err := c.FetchAll(ctx)
 79→	if err != nil {
 80→		return nil, err
 81→	}
 82→	if query == "" {
 83→		return all, nil
 84→	}
 85→
 86→	q := strings.ToLower(query)
 87→	var matches []RegistryServer
 88→	for _, srv := range all {
 89→		if strings.Contains(strings.ToLower(srv.Name), q) ||
 90→			strings.Contains(strings.ToLower(srv.Description), q) {
 91→			matches = append(matches, srv)
 92→		}
 93→	}
 94→	return matches, nil
 95→}
 96→
 97→// Get returns a single server by registry ID (name).
 98→func (c *Client) Get(ctx context.Context, registryID string) (*RegistryServer, error) {
 99→	all, err := c.FetchAll(ctx)
100→	if err != nil {
101→		return nil, err
102→	}
103→	for _, srv := range all {
104→		if srv.Name == registryID {
105→			return &srv, nil
106→		}
107→	}
108→	return nil, nil
109→}
110→
111→func (c *Client) fetchFromRegistry(ctx context.Context) ([]RegistryServer, error) {
112→	url := c.baseURL + "/v0/servers"
113→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
114→	if err != nil {
115→		return nil, fmt.Errorf("registry: create request: %w", err)
116→	}
117→	req.Header.Set("Accept", "application/json")
118→
119→	resp, err := c.httpClient.Do(req)
120→	if err != nil {
121→		return nil, fmt.Errorf("registry: fetch: %w", err)
122→	}
123→	defer resp.Body.Close()
124→
125→	if resp.StatusCode != http.StatusOK {
126→		return nil, fmt.Errorf("registry: unexpected status %d", resp.StatusCode)
127→	}
128→
129→	var result RegistryResponse
130→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
131→		return nil, fmt.Errorf("registry: decode: %w", err)
132→	}
133→	return result.Servers, nil
134→}
