1363→func (s *apiServer) InstallMarketplaceServer(w http.ResponseWriter, r *http.Request, registryId string) {
1364→	ctx := r.Context()
1365→
1366→	srv, err := s.registryClient.Get(ctx, registryId)
1367→	if err != nil {
1368→		writeError(w, http.StatusBadGateway, "registry_error", err.Error())
1369→		return
1370→	}
1371→	if srv == nil {
1372→		writeError(w, http.StatusNotFound, "not_found", "server not found in registry: "+registryId)
1373→		return
1374→	}
1375→
1376→	// Derive command from the best available package.
1377→	command, envVars := deriveCommand(srv)
1378→
1379→	id := "mcp_" + s.newID()
1380→	now := time.Now().UTC()
1381→	stopped := api.MCPServerConfigStatusStopped
1382→	local := api.Local
1383→	config := api.MCPServerConfig{
1384→		Id:         &id,
1385→		Name:       srv.Name,
1386→		Command:    command,
1387→		Status:     &stopped,
1388→		Mode:       &local,
1389→		RegistryId: &registryId,
1390→		CreatedAt:  &now,
1391→	}
1392→	if srv.Description != "" {
1393→		config.Description = &srv.Description
1394→	}
1395→
1396→	// Pre-populate env map with empty values for required env vars.
1397→	if len(envVars) > 0 {
1398→		envMap := make(map[string]string, len(envVars))
1399→		for _, ev := range envVars {
1400→			envMap[ev.Name] = ""
1401→		}
1402→		config.Env = &envMap
1403→	}
1404→
1405→	if err := s.mcpServers.Create(ctx, config); err != nil {
1406→		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
1407→		return
1408→	}
1409→
1410→	// Build required credentials list.
1411→	var reqCreds []api.RequiredEnvVar
1412→	for _, ev := range envVars {
1413→		reqCreds = append(reqCreds, api.RequiredEnvVar{
1414→			Name:        ev.Name,
1415→			Description: &ev.Description,
1416→			Required:    &ev.Required,
1417→		})
1418→	}
1419→
1420→	result := api.InstallResult{
1421→		Server: config,
1422→	}
1423→	if len(reqCreds) > 0 {
1424→		result.RequiredCredentials = &reqCreds
1425→	}
1426→
1427→	writeJSON(w, http.StatusCreated, result)
1428→}
1429→
1430→// deriveCommand picks the best package from a registry server and returns
1431→// the command array and required env vars.
1432→func deriveCommand(srv *registry.RegistryServer) ([]string, []registry.EnvVar) {
1433→	// Prefer npm packages (most common for MCP servers).
1434→	for _, pkg := range srv.Packages {
1435→		if pkg.RegistryType == "npm" {
1436→			cmd := []string{"npx", "-y", pkg.Name}
1437→			if pkg.Runtime.Args != nil {
1438→				cmd = append(cmd, pkg.Runtime.Args...)
1439→			}
1440→			return cmd, pkg.EnvVars
1441→		}
1442→	}
1443→
1444→	// Fall back to any package with a runtime command.
1445→	for _, pkg := range srv.Packages {
1446→		if pkg.Runtime.Command != "" {
1447→			cmd := []string{pkg.Runtime.Command}
1448→			cmd = append(cmd, pkg.Runtime.Args...)
1449→			return cmd, pkg.EnvVars
1450→		}
1451→	}

