				{Server: registry.RegistryServer{Name: "server-4", Description: "Fourth"}},
			},
			cursor: "page3",
		},
		"page3": {
			entries: []registry.RegistryEntry{
				{Server: registry.RegistryServer{Name: "server-5", Description: "Fifth"}},
			},
			cursor: "",
		},
