 14→const (
 15→	// DefaultRegistryURL is the official MCP Registry API endpoint.
 16→	DefaultRegistryURL = "https://registry.modelcontextprotocol.io"
 17→
 18→	// DefaultCacheTTL is how long the server list is cached.
 19→	DefaultCacheTTL = 15 * time.Minute
 20→)
 21→
 22→// Client fetches and caches MCP server metadata from the official registry.
 23→type Client struct {
 24→	baseURL    string
 25→	httpClient *http.Client
 26→	cacheTTL   time.Duration
 27→
 28→	mu        sync.RWMutex
 29→	cached    []RegistryServer
 30→	cachedAt  time.Time
 31→}
 32→
 33→// NewClient creates a registry client with sensible defaults.
 34→func NewClient(httpClient *http.Client) *Client {
 35→	if httpClient == nil {
 36→		httpClient = &http.Client{Timeout: 30 * time.Second}
 37→	}
 38→	return &Client{
 39→		baseURL:    DefaultRegistryURL,
 40→		httpClient: httpClient,
 41→		cacheTTL:   DefaultCacheTTL,
 42→	}
 43→}
 44→
 45→// WithBaseURL overrides the registry URL (useful for testing).
 46→func (c *Client) WithBaseURL(url string) *Client {
 47→	c.baseURL = url
 48→	return c
 49→}
 50→
 51→// FetchAll returns every server from the registry, using the cache if fresh.
 52→func (c *Client) FetchAll(ctx context.Context) ([]RegistryServer, error) {
 53→	c.mu.RLock()
 54→	if c.cached != nil && time.Since(c.cachedAt) < c.cacheTTL {
 55→		result := make([]RegistryServer, len(c.cached))
 56→		copy(result, c.cached)
 57→		c.mu.RUnlock()
